// Search crops by name in either language
export function searchCrops(query: string): CropInfo[] {
  const q = query.toLowerCase().trim();
  if (!q) return rwandaCrops;
  return rwandaCrops.filter(
    (c) =>
      c.name_en.toLowerCase().includes(q) ||
      c.name_ki.toLowerCase().includes(q) ||
      c.category_en.toLowerCase().includes(q) ||
      c.category_ki.toLowerCase().includes(q)
  );
}

// Get crop categories
export function getCropCategories(): { en: string; ki: string }[] {
  const seen = new Set<string>();
  const cats: { en: string; ki: string }[] = [];
  for (const c of rwandaCrops) {
    if (!seen.has(c.category_en)) {
      seen.add(c.category_en);
      cats.push({ en: c.category_en, ki: c.category_ki });
    }
  }
  return cats;
}
